mapper.select:
SELECT P.PROJECT_NO, P.REG_EMP_NO, P.DEPT_CD, P.PROJECT_NM, P.PROJECT_DESC, P.PROJECT_STAT_CD, P.START_DTM, P.END_DTM, P.USE_YN, P.MAIN_IMG_PATH, D.DEPT_NM AS DEPT_NM, E.EMP_NM AS REG_EMP_NM, D.DEPT_HEAD_EMP_NO AS DEPT_HEAD_EMP_NO, EH.EMP_NM AS DEPT_HEAD_EMP_NM FROM PROJECT P JOIN DEPT D ON D.DEPT_CD = P.DEPT_CD LEFT JOIN EMP E ON E.EMP_NO = P.REG_EMP_NO LEFT JOIN EMP EH ON EH.EMP_NO = D.DEPT_HEAD_EMP_NO WHERE D.DEL_YN = 'N'
AND P.DEPT_CD = #{cond.deptCd}
AND P.PROJECT_STAT_CD = #{cond.projectStatCd}
AND P.USE_YN = #{cond.useYn}
AND ( P.PROJECT_NM LIKE '%' || #{cond.keyword} || '%' OR P.PROJECT_DESC LIKE '%' || #{cond.keyword} || '%' )
ORDER BY P.PROJECT_NO DESC

mapper.update:
UPDATE PROJECT
SET USE_YN = #{useYn}
WHERE PROJECT_NO = #{projectNo}
